--职业奖池
require "config.Define"
JobPondConfig = {}
JobPondConfig.jobPond = {}      --储存着所有的奖池
JobPondConfig.weightSum = 0

function JobPondConfig:init(configs)
    for _, config in pairs(configs) do
        local item = {}
        item.id = tonumber(config.id)
        item.poolId = config.poolId
        item.amount = config.amount
        item.weight = tonumber(config.weight)
        item.price = config.consumeCube
        self.jobPond[item.id] = item
        self.weightSum = self.weightSum + item.weight
    end
end

--随机一个奖池子来
function JobPondConfig:randomJobPond()
    local random = math.random(1, self.weightSum)
    local weight = 0
    for _, item in pairs(self.jobPond) do
        weight = weight + item.weight
        if weight >= random then
            return item
        end
    end
end

--通过奖池的id 得到奖池
function JobPondConfig:getJobPondById(id)
    local jobPond = self.jobPond[tonumber(id)]
    if jobPond ~= nil then
        return jobPond
    end
end

return JobPondConfig